logic clk, rst_n;
logic [2:0] CS;
parameter IDLE = 3'd0;
always_ff @(posedge clk, negedge rst_n) begin
  if (~rst_n)
    CS <= IDLE;
  else
    CS <= CS + 1;
end

typedef enum logic [1:0] {IDLE, ACTIVE, DONE} state_t;
state_t CS, NS;
logic clk, rst_n;
always_ff @(posedge clk, negedge rst_n) begin
  if (~rst_n)
    CS <= IDLE;
  else
    CS <= NS;
end
always_comb begin
  case (CS)
    IDLE:   NS = ACTIVE;
    ACTIVE: NS = DONE;
    default: NS = IDLE;
  endcase
end

logic clk, rst_n;
logic [2:0] CS, NS;
logic [31:0] addr_Q, addr_i;
logic req_Q, enable_pipe, clear_pipe;
always_ff @(posedge clk, negedge rst_n) begin
  if (~rst_n) begin
    CS    <= '0;
    addr_Q <= '0;
    req_Q  <= '0;
  end else begin
    CS <= NS;
    if (enable_pipe) begin
      req_Q  <= 1'b1;
      addr_Q <= addr_i;
    end else if (clear_pipe)
      req_Q <= '0;
  end
end

logic clk, rst_n, enable_pipe, clear_pipe;
logic req_Q;
always_ff @(posedge clk, negedge rst_n) begin
  if (~rst_n)
    req_Q <= '0;
  else begin
    if (enable_pipe)
      req_Q <= 1'b1;
    else if (clear_pipe)
      req_Q <= '0;
  end
end
